#!/usr/bin/env python3
import os
from sys import stdout

# Define our input and output paths
RAW_PATH: str = os.path.expanduser("~/.cache/sequences.raw")
OUTPUT_PATH: str = os.path.expanduser("~/.cache/sequences")

# Main function
def main():
    # Error out if raw sequences are missing
    if not os.path.exists(RAW_PATH):
        raise FileNotFoundError(f"Missing raw template: {RAW_PATH}")
    
    # Read the text representation generated by Matugen
    with open(RAW_PATH, "r") as f:
        # Split by line and strip out any padding or empty newlines
        lines: list[str] = [line.strip() for line in f if line.strip()]
    
    # Join everything into a single seamless line of text
    raw_content: str = "".join(lines)

    # Convert literal "\x1b" text strings into real raw binary escape bytes
    sequence_bytes:bytes = raw_content.encode("utf-8").decode("unicode_escape").encode("utf-8")
    
    # Save the binary sequences file
    with open(OUTPUT_PATH, "wb") as f:
        _ =f.write(sequence_bytes)
    
    # Flush the binary sequence to the active terminal screen
    _ = stdout.buffer.write(sequence_bytes)
    _ = stdout.flush()

    # Print the "wal --preview" style block display:
    # Header
    print("\n  \x1b[1mMatugen Palette Preview\x1b[0m")
    print("  " + "—" * 32)
    # Row 1: Normal Colors (0-7)
    row1: str = "  "
    for i in range(8):
        row1 += f"\x1b[48;5;{i}m      \x1b[0m"
    print(row1)
    # Row 2: Bright Colors (8-15)
    row2: str = "  "
    for i in range(8, 16):
        row2 += f"\x1b[48;5;{i}m      \x1b[0m"
    print(row2)
    # Footer
    print("  " + "—" * 32 + "\n")

# Execution
if __name__ == "__main__":
    main()